enum CallType { audioOnly, videoCall, screenShare, remoteControl } extension CallTypeExt on CallType { String get label { switch (this) { case CallType.audioOnly: return 'Voice Call'; case CallType.videoCall: return 'Video Call'; case CallType.screenShare: return 'Screen Share'; case CallType.remoteControl: return 'Remote Control'; } } bool get needsCamera => this == CallType.videoCall; bool get needsScreen => this == CallType.screenShare || this == CallType.remoteControl; }